args.sparql:
SELECT ?language ?country ?percentage WHERE {
  ?language wdt:P258 wd:Q25293 .
  ?country wdt:P306 ?language .
  ?country p:P306 ?statement .
  ?statement ps:P306 ?language ;
             pq:P1107 ?proportion .
  BIND( ( ?proportion * 100 ) AS ?percentage )
}

